// Init: generate stable executionId, extract webhook payload
const webhookBody = $input.first().json.body || $input.first().json;
const campaignId = webhookBody.campaignId || '';
const criteria = webhookBody.criteria || {};
const userEmail = webhookBody.userEmail || 'danny.reszka@gmail.com';

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

// One stable ID per workflow execution — reused on retries
const executionId = ($execution && $execution.id) ? $execution.id.replace(/-/g, '').slice(0, 32) : uuidv4();
const backendUrl = webhookBody.backendUrl || '';
const backendApiKey = webhookBody.backendApiKey || '';
const apolloApiKey = webhookBody.apolloApiKey || '';
const serperApiKey = webhookBody.serperApiKey || '';
const anthropicApiKey = webhookBody.anthropicApiKey || '';

return [{ json: {
  executionId,
  campaignId,
  criteria,
  userEmail,
  backendUrl,
  backendApiKey,
  apolloApiKey,
  serperApiKey,
  anthropicApiKey,
  updatedAt: new Date().toISOString(),
  source: 'n8n',
} }];

// Process Apollo results — normalise into per-company items
const initData = $('Code: Init Execution').first().json;
const existingLeadsResp = $('HTTP: GET Existing Leads').first().json;
const apolloData = $input.first().json;

const existingLeads = (existingLeadsResp.data || []);
const people = apolloData.people || apolloData.results || [];

if (people.length === 0) {
  // No Apollo results — mark campaign failed
  return [{ json: {
    ...initData,
    existingLeads,
    noResults: true,
    companyName: '__NO_RESULTS__',
    itemIndex: 0,
  } }];
}

return people.map((p, idx) => {
  const org = p.organization || {};
  const rawSite = org.website_url || org.primary_domain || '';
  const domain = rawSite.replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0].toLowerCase();

  return { json: {
    personName: p.name || ((p.first_name || '') + ' ' + (p.last_name || '')).trim(),
    personTitle: p.title || '',
    personEmail: p.email || '',
    personPhone: (p.phone_numbers && p.phone_numbers[0]) ? p.phone_numbers[0].raw_number : '',
    companyName: org.name || '',
    domain,
    website: rawSite,
    industry: org.industry || '',
    headcount: org.num_employees || null,
    fundingStage: org.funding_stage || '',
    linkedinUrl: org.linkedin_url || p.linkedin_url || '',
    // Propagate context
    executionId: initData.executionId,
    campaignId: initData.campaignId,
    criteria: initData.criteria,
    userEmail: initData.userEmail,
    backendUrl: initData.backendUrl,
    backendApiKey: initData.backendApiKey,
    serperApiKey: initData.serperApiKey,
    anthropicApiKey: initData.anthropicApiKey,
    updatedAt: initData.updatedAt,
    source: initData.source,
    existingLeads,
    itemIndex: idx,
  } };
});

// Parse Claude score, check qualifying, check duplicate
const lead = $('Loop: Per Lead').item.json;
const claudeResp = $input.first().json;

// Parse score from Claude response
let score = 0;
let reasoning = '';
try {
  const text = (claudeResp.content && claudeResp.content[0]) ? claudeResp.content[0].text : '';
  reasoning = text.slice(0, 200);
  const m = text.match(/Score:\s*(\d+(?:\.\d+)?)/i) ||
             text.match(/(\d+(?:\.\d+)?)\s*\/\s*10/i) ||
             text.match(/\b(10|[1-9])\b/);
  if (m) score = parseFloat(m[1]);
} catch (e) {
  reasoning = 'parse-error: ' + e.message;
}

const QUALIFY_THRESHOLD = 6;
const isQualifying = score >= QUALIFY_THRESHOLD;

// Duplicate check: match by domain then by company name
const existingLeads = lead.existingLeads || [];
const domain = (lead.domain || '').toLowerCase();
const companyName = (lead.companyName || '').toLowerCase().trim();
let isDuplicate = false;
let existingLeadId = null;

if (domain) {
  const match = existingLeads.find(l => {
    const ld = ((l.website || l.domain || '')
      .replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0]).toLowerCase();
    return ld && ld === domain;
  });
  if (match) { isDuplicate = true; existingLeadId = match.id; }
}
if (!isDuplicate && companyName) {
  const match = existingLeads.find(l =>
    (l.company || l.name || '').toLowerCase().trim() === companyName
  );
  if (match) { isDuplicate = true; existingLeadId = match.id; }
}

// Per-lead requestId: stable per execution + lead index
const leadRequestId = lead.executionId + '-lead-' + lead.itemIndex;

return [{ json: {
  ...lead,
  score,
  reasoning,
  isQualifying,
  isDuplicate,
  existingLeadId,
  leadRequestId,
  // Create new lead only when qualifying AND not a duplicate
  shouldCreate: isQualifying && !isDuplicate,
  // Link existing lead only when qualifying AND is a duplicate
  shouldLink: isQualifying && isDuplicate,
} }];
